import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.Pywvta2k.js";const f=JSON.parse('{"title":"医易身心同调","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/09-医易同源/05-医易身心同调.md","filePath":"tcm-data/09-医易同源/05-医易身心同调.md","lastUpdated":1781084559000}'),s={name:"tcm-data/09-医易同源/05-医易身心同调.md"};function d(r,t,i,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="医易身心同调" tabindex="-1">医易身心同调 <a class="header-anchor" href="#医易身心同调" aria-label="Permalink to &quot;医易身心同调&quot;">​</a></h1><blockquote><p>从医易结合的视角，打通身体健康、情绪管理、心灵成长的完整路径 身心同调·完整生命方案</p></blockquote><hr><h2 id="一、身心同调——为什么医易能做到" tabindex="-1">一、身心同调——为什么医易能做到？ <a class="header-anchor" href="#一、身心同调——为什么医易能做到" aria-label="Permalink to &quot;一、身心同调——为什么医易能做到？&quot;">​</a></h2><h3 id="中医治身-易学调心" tabindex="-1">中医治身，易学调心 <a class="header-anchor" href="#中医治身-易学调心" aria-label="Permalink to &quot;中医治身，易学调心&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">中医</th><th style="text-align:left;">易学</th></tr></thead><tbody><tr><td style="text-align:left;">关注</td><td style="text-align:left;">气血、脏腑、经络</td><td style="text-align:left;">阴阳、卦象、爻位</td></tr><tr><td style="text-align:left;">方法</td><td style="text-align:left;">汤药、针灸、导引</td><td style="text-align:left;">观象、修德、知变</td></tr><tr><td style="text-align:left;">层次</td><td style="text-align:left;">身体（形）</td><td style="text-align:left;">心神（神）</td></tr><tr><td style="text-align:left;">结合</td><td style="text-align:left;">形神一体</td><td style="text-align:left;">身心不二</td></tr></tbody></table><h3 id="孙思邈的-三者兼备" tabindex="-1">孙思邈的&quot;三者兼备&quot; <a class="header-anchor" href="#孙思邈的-三者兼备" aria-label="Permalink to &quot;孙思邈的&quot;三者兼备&quot;&quot;">​</a></h3><blockquote><p><strong>孙思邈</strong>：「上医医国，中医医人，下医医病。」 <strong>又云</strong>：「不知易，不足以言太医。」</p></blockquote><p>医易结合 = 上医之路——不仅能治病，还能<strong>调心、悟道、安身立命</strong>。</p><hr><h2 id="二、身——针对患者的中医方案" tabindex="-1">二、身——针对患者的中医方案 <a class="header-anchor" href="#二、身——针对患者的中医方案" aria-label="Permalink to &quot;二、身——针对患者的中医方案&quot;">​</a></h2><h3 id="身体主要问题" tabindex="-1">身体主要问题 <a class="header-anchor" href="#身体主要问题" aria-label="Permalink to &quot;身体主要问题&quot;">​</a></h3><p>水寒土湿木郁 → 相火不降（上热下寒）</p><h3 id="治疗方案" tabindex="-1">治疗方案 <a class="header-anchor" href="#治疗方案" aria-label="Permalink to &quot;治疗方案&quot;">​</a></h3><ul><li><strong>处方</strong>：温潜黄芽天魂汤</li><li><strong>针灸</strong>：关元、足三里、命门、太冲</li><li><strong>饮食</strong>：温热饮食、忌生冷、理中培土粥</li><li><strong>运动</strong>：站桩+八段锦+温和瑜伽</li></ul><hr><h2 id="三、心——针对患者的易学方案" tabindex="-1">三、心——针对患者的易学方案 <a class="header-anchor" href="#三、心——针对患者的易学方案" aria-label="Permalink to &quot;三、心——针对患者的易学方案&quot;">​</a></h2><h3 id="卦象分析" tabindex="-1">卦象分析 <a class="header-anchor" href="#卦象分析" aria-label="Permalink to &quot;卦象分析&quot;">​</a></h3><p>患者的主卦：<strong>坎☵水寒 + 坤☷土湿 + 震☳木郁</strong></p><h3 id="情绪调节" tabindex="-1">情绪调节 <a class="header-anchor" href="#情绪调节" aria-label="Permalink to &quot;情绪调节&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">问题</th><th style="text-align:left;">易学智慧</th><th style="text-align:left;">具体做法</th></tr></thead><tbody><tr><td style="text-align:left;">木郁→烦躁</td><td style="text-align:left;"><strong>震卦</strong>：「君子以恐惧修省」</td><td style="text-align:left;">静坐观呼吸，不压不纵</td></tr><tr><td style="text-align:left;">水寒→无力</td><td style="text-align:left;"><strong>坎卦</strong>：「维心亨，行有尚」</td><td style="text-align:left;">困难时保持内心通透</td></tr><tr><td style="text-align:left;">整体</td><td style="text-align:left;"><strong>否卦䷋→泰卦䷊</strong></td><td style="text-align:left;">从&quot;天地不交&quot;到&quot;天地交泰&quot;</td></tr></tbody></table><h3 id="太极站桩法-身心同调" tabindex="-1">太极站桩法（身心同调） <a class="header-anchor" href="#太极站桩法-身心同调" aria-label="Permalink to &quot;太极站桩法（身心同调）&quot;">​</a></h3><p><strong>站桩要点</strong>：</p><ol><li>双脚与肩同宽、膝盖微屈</li><li>双手抱圆在胸前（如抱太极）</li><li>意守关元（下丹田）——引火归原</li><li>自然呼吸，不强调</li></ol><p><strong>每次15-30分钟，每天一次</strong>——这是&quot;动中求静、静中生气&quot;最好的身心同调法。</p><h3 id="卦象养生三字诀-阳虚型" tabindex="-1">卦象养生三字诀（阳虚型） <a class="header-anchor" href="#卦象养生三字诀-阳虚型" aria-label="Permalink to &quot;卦象养生三字诀（阳虚型）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>坎水寒 → 温之（附子+关元灸）</span></span>
<span class="line"><span>坤土湿 → 燥之（茯苓+站桩）</span></span>
<span class="line"><span>震木郁 → 达之（桂枝+疏肝）</span></span>
<span class="line"><span>离火浮 → 潜之（龙牡+静坐）</span></span></code></pre></div><hr><h2 id="四、身——针对患者的中医方案" tabindex="-1">四、身——针对患者的中医方案 <a class="header-anchor" href="#四、身——针对患者的中医方案" aria-label="Permalink to &quot;四、身——针对患者的中医方案&quot;">​</a></h2><h3 id="身体主要问题-1" tabindex="-1">身体主要问题 <a class="header-anchor" href="#身体主要问题-1" aria-label="Permalink to &quot;身体主要问题&quot;">​</a></h3><p>中虚血少 → 肝郁化火 → 相火浮越（上热下寒·虚证）</p><h3 id="治疗方案-1" tabindex="-1">治疗方案 <a class="header-anchor" href="#治疗方案-1" aria-label="Permalink to &quot;治疗方案&quot;">​</a></h3><ul><li><strong>处方</strong>：加减黄芽地魄汤</li><li><strong>针灸</strong>：三阴交、足三里、神门</li><li><strong>饮食</strong>：山药小米粥+蛋奶+桂圆枸杞</li><li><strong>运动</strong>：八段锦+散步+不劳累</li></ul><hr><h2 id="五、心——针对患者的易学方案" tabindex="-1">五、心——针对患者的易学方案 <a class="header-anchor" href="#五、心——针对患者的易学方案" aria-label="Permalink to &quot;五、心——针对患者的易学方案&quot;">​</a></h2><h3 id="卦象分析-1" tabindex="-1">卦象分析 <a class="header-anchor" href="#卦象分析-1" aria-label="Permalink to &quot;卦象分析&quot;">​</a></h3><p>患者的主卦：<strong>坤☷中虚 + 震☳木郁化火 + 离☲浮越</strong></p><h3 id="情绪调节-1" tabindex="-1">情绪调节 <a class="header-anchor" href="#情绪调节-1" aria-label="Permalink to &quot;情绪调节&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">问题</th><th style="text-align:left;">易学智慧</th><th style="text-align:left;">具体做法</th></tr></thead><tbody><tr><td style="text-align:left;">烦躁</td><td style="text-align:left;"><strong>坤卦</strong>：「厚德载物」</td><td style="text-align:left;">大地一样包容，不急于解决</td></tr><tr><td style="text-align:left;">疲惫</td><td style="text-align:left;"><strong>复卦䷗</strong>：「一阳来复」</td><td style="text-align:left;">允许自己休息，在休息中恢复</td></tr><tr><td style="text-align:left;">月经不调</td><td style="text-align:left;"><strong>泰卦䷊</strong>→动静交替</td><td style="text-align:left;">接受生命周期（月信如月相）</td></tr></tbody></table><h3 id="静坐养阴法-阴虚型" tabindex="-1">静坐养阴法（阴虚型） <a class="header-anchor" href="#静坐养阴法-阴虚型" aria-label="Permalink to &quot;静坐养阴法（阴虚型）&quot;">​</a></h3><p><strong>静坐要点</strong>：</p><ol><li>静坐（盘腿或坐椅子皆可）</li><li>意守膻中（胸口）——养心阴</li><li>配合观想：月华从头顶注入全身</li><li>每次10-20分钟，睡前最佳</li></ol><h3 id="卦象养生三字诀-阴虚型" tabindex="-1">卦象养生三字诀（阴虚型） <a class="header-anchor" href="#卦象养生三字诀-阴虚型" aria-label="Permalink to &quot;卦象养生三字诀（阴虚型）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>坤土虚 → 补之（人参+山药粥）</span></span>
<span class="line"><span>震木郁 → 舒之（柴胡+拍肝经）</span></span>
<span class="line"><span>离火浮 → 敛之（酸枣仁+静坐）</span></span>
<span class="line"><span>坎水亏 → 润之（熟地+早睡）</span></span></code></pre></div><hr><h2 id="六、身心同调的七个具体练习" tabindex="-1">六、身心同调的七个具体练习 <a class="header-anchor" href="#六、身心同调的七个具体练习" aria-label="Permalink to &quot;六、身心同调的七个具体练习&quot;">​</a></h2><h3 id="每日七件事" tabindex="-1">每日七件事 <a class="header-anchor" href="#每日七件事" aria-label="Permalink to &quot;每日七件事&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">练习</th><th style="text-align:left;">身</th><th style="text-align:left;">心</th><th style="text-align:left;">时长</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>晨起</strong></td><td style="text-align:left;">站桩/静坐</td><td style="text-align:left;">调气</td><td style="text-align:left;">定心</td><td style="text-align:left;">15分钟</td></tr><tr><td style="text-align:left;"><strong>早餐</strong></td><td style="text-align:left;">姜枣茶/小米粥</td><td style="text-align:left;">养中</td><td style="text-align:left;">感恩</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;"><strong>上午</strong></td><td style="text-align:left;">晒太阳</td><td style="text-align:left;">补阳</td><td style="text-align:left;">开怀</td><td style="text-align:left;">15分钟</td></tr><tr><td style="text-align:left;"><strong>午后</strong></td><td style="text-align:left;">午休</td><td style="text-align:left;">养阴</td><td style="text-align:left;">放空</td><td style="text-align:left;">20分钟</td></tr><tr><td style="text-align:left;"><strong>傍晚</strong></td><td style="text-align:left;">散步</td><td style="text-align:left;">运化</td><td style="text-align:left;">观察自然</td><td style="text-align:left;">20分钟</td></tr><tr><td style="text-align:left;"><strong>晚间</strong></td><td style="text-align:left;">泡脚</td><td style="text-align:left;">引火归原</td><td style="text-align:left;">放下</td><td style="text-align:left;">15分钟</td></tr><tr><td style="text-align:left;"><strong>睡前</strong></td><td style="text-align:left;">静坐/数息</td><td style="text-align:left;">归元</td><td style="text-align:left;">安宁</td><td style="text-align:left;">10分钟</td></tr></tbody></table><hr><h2 id="七、从-治病-到-活出生命" tabindex="-1">七、从&quot;治病&quot;到&quot;活出生命&quot; <a class="header-anchor" href="#七、从-治病-到-活出生命" aria-label="Permalink to &quot;七、从&quot;治病&quot;到&quot;活出生命&quot;&quot;">​</a></h2><blockquote><p><strong>《易经》</strong>：「一阴一阳之谓道，继之者善也，成之者性也。」 <strong>《黄帝内经》</strong>：「上古之人，其知道者，法于阴阳，和于术数。」</p></blockquote><p>医易的最高境界不是&quot;用药治病&quot;——而是**&quot;知道&quot;<strong>、</strong>&quot;法于阴阳&quot;<strong>、</strong>&quot;和于术数&quot;<strong>，最终</strong>活出自然**。</p><table tabindex="0"><thead><tr><th style="text-align:left;">层次</th><th style="text-align:left;">表现</th><th style="text-align:left;">患者（男）现在</th><th style="text-align:left;">下一步</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>治病</strong></td><td style="text-align:left;">吃药、扎针</td><td style="text-align:left;">✅ 已开始</td><td style="text-align:left;">坚持</td></tr><tr><td style="text-align:left;"><strong>调身</strong></td><td style="text-align:left;">饮食、运动</td><td style="text-align:left;">✅ 已做</td><td style="text-align:left;">优化</td></tr><tr><td style="text-align:left;"><strong>调心</strong></td><td style="text-align:left;">静坐、觉知</td><td style="text-align:left;">⚠️ 打坐中</td><td style="text-align:left;">加强</td></tr><tr><td style="text-align:left;"><strong>知道</strong></td><td style="text-align:left;">理解阴阳</td><td style="text-align:left;">⬜</td><td style="text-align:left;">读易</td></tr><tr><td style="text-align:left;"><strong>合道</strong></td><td style="text-align:left;">自然生活</td><td style="text-align:left;">⬜</td><td style="text-align:left;">持续</td></tr></tbody></table><hr><p><em>本条目为精简框架版。可继续扩展至&quot;易经64卦与人生健康&quot;等深层次内容。</em></p>`,55)])])}const y=e(s,[["render",d]]);export{f as __pageData,y as default};
